class Solution:

def binary_search(self, nums: list[int], target: int) -> bool:
    if target < nums[0] or target > nums[-1]: return False
    left, right = 0, len(nums) - 1
    while left <= right:
        mid = left + (right - left) // 2
        if nums[mid] == target:
            return True
        elif target < nums[mid]:
            right = mid - 1
        else:
            left = mid + 1
    return False

def main():
    nums = list(map(int, input().split()))
    n = int(input())
    target = int(input())
    solver = Solution()
    print(solver.binary_search(nums, target))
main()

